			target.Send(map[string]any{"type": "system", "message": fmt.Sprintf("You received %d %s (total=%d)", qty, item, newQty)})
			c.Send(map[string]any{"type": "system", "message": fmt.Sprintf("Gave %d %s to %s (total=%d)", qty, item, target.name, newQty)})
