func (s *Server) listCommandsForRole(r Role) []string {
	s.mu.RLock()
	defer s.mu.RUnlock()
	var out []string
	for name, cmd := range s.commands {
		if roleAtLeast(r, cmd.MinRole) {
			out = append(out, "/"+name)
		}
	}
	// stable-ish: simple sort
	for i := 0; i < len(out); i++ {
		for j := i + 1; j < len(out); j++ {
			if out[j] < out[i] {
				out[i], out[j] = out[j], out[i]
			}
		}
	}
	return out
}

func (s *Server) broadcastSystem(msg string) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, cl := range s.clients {
		cl.Send(map[string]any{"type": "system", "message": msg})
	}
}

func (s *Server) addClient(c *Client) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.clients[c.id] = c
	s.nameIndex[strings.ToLower(c.name)] = c.id
}

func (s *Server) removeClient(id string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	if cl, ok := s.clients[id]; ok {
		delete(s.nameIndex, strings.ToLower(cl.name))
	}
	delete(s.clients, id)
}

func (s *Server) getClientByName(name string) *Client {
	s.mu.RLock()
	defer s.mu.RUnlock()
	id := s.nameIndex[strings.ToLower(strings.TrimSpace(name))]
	if id == "" {
		return nil
	}
	return s.clients[id]
}

func (s *Server) isBanned(id string) (bool, time.Time) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	until, ok := s.bans[id]
	if !ok {
		return false, time.Time{}
	}
	if time.Now().After(until) {
		return false, time.Time{}
	}
	return true, until
}

func newID() string {
	var b [16]byte
	_, _ = rand.Read(b[:])
	return hex.EncodeToString(b[:])
}

type incomingMsg struct {
	Type    string `json:"type"`
	Message string `json:"message"`
}

func (s *Server) handleConn(conn net.Conn) {
	defer func() { _ = conn.Close() }()

	_ = conn.SetReadDeadline(time.Now().Add(10 * time.Second))
	br := bufio.NewReader(conn)
	line, err := br.ReadString('\n')
	if err != nil {
		return
	}
	_ = conn.SetReadDeadline(time.Time{})

	var hello map[string]any
	if err := json.Unmarshal([]byte(strings.TrimSpace(line)), &hello); err != nil {
		return
	}

	name, _ := hello["name"].(string)
	name = strings.TrimSpace(name)
	if name == "" {
		name = "Player"
	}
	roleStr, _ := hello["role"].(string)
	role := parseRole(roleStr)

	clientID, _ := hello["client_id"].(string)
	clientID = strings.TrimSpace(clientID)
	if clientID == "" {
		clientID = newID()
	}

	if banned, until := s.isBanned(clientID); banned {
		_ = writeLine(conn, map[string]any{"type": "system", "message": fmt.Sprintf("Banned until %s", until.Format(time.RFC3339))})
		return
	}

	c := &Client{
		id:     clientID,
		name:   name,
		role:   role,
		conn:   conn,
		server: s,
		closed: make(chan struct{}),
	}

	s.addClient(c)
	defer func() {
		s.removeClient(c.id)
		c.Close()
	}()

	c.Send(map[string]any{"type": "system", "message": fmt.Sprintf("Welcome %s (role=%s, id=%s)", c.name, c.role, c.id)})
	s.broadcastSystem(fmt.Sprintf("%s joined", c.name))

	sc := bufio.NewScanner(br)
	sc.Buffer(make([]byte, 0, 4096), 1024*1024)
	for sc.Scan() {
		raw := strings.TrimSpace(sc.Text())
		if raw == "" {
			continue
		}

		var im incomingMsg
		if err := json.Unmarshal([]byte(raw), &im); err != nil {
			im.Type = "chat"
			im.Message = raw
		}

		switch strings.ToLower(strings.TrimSpace(im.Type)) {
		case "chat":
			s.handleChat(context.Background(), c, im.Message)
		default:
			c.Send(map[string]any{"type": "system", "message": "Unknown message type"})
		}
	}
}

func (s *Server) handleChat(ctx context.Context, c *Client, msg string) {
	msg = strings.TrimSpace(msg)
	if msg == "" {
		return
	}
	if strings.HasPrefix(msg, "/") {
		s.handleCommand(ctx, c, msg)
		return
	}
	s.mu.RLock()
	for _, cl := range s.clients {
		cl.Send(map[string]any{"type": "chat", "from": c.name, "message": msg})
	}
	s.mu.RUnlock()
}

func (s *Server) handleCommand(ctx context.Context, c *Client, line string) {
	parts := splitArgs(strings.TrimSpace(line))
	if len(parts) == 0 {
		return
	}
	cmdName := strings.ToLower(strings.TrimPrefix(parts[0], "/"))
	args := parts[1:]

	cmd := s.commands[cmdName]
	if cmd == nil {
		c.Send(map[string]any{"type": "system", "message": "Unknown command. Try /help"})
		return
	}
	if !roleAtLeast(c.role, cmd.MinRole) {
		c.Send(map[string]any{"type": "system", "message": "Permission denied"})
		return
	}
	if err := cmd.Handler(ctx, s, c, args); err != nil {
		c.Send(map[string]any{"type": "system", "message": err.Error()})
	}
}

func splitArgs(s string) []string {
	var out []string
	var cur strings.Builder
	inQuote := false
	esc := false
	for _, r := range s {
		if esc {
			cur.WriteRune(r)
			esc = false
			continue
		}
		switch r {
		case '\\':
			esc = true
		case '"':
			inQuote = !inQuote
		case ' ', '\t', '\n', '\r':
			if inQuote {
				cur.WriteRune(r)
			} else {
				if cur.Len() > 0 {
					out = append(out, cur.String())
					cur.Reset()
				}
			}
		default:
			cur.WriteRune(r)
		}
	}
	if cur.Len() > 0 {
		out = append(out, cur.String())
	}
	return out
}

func writeLine(conn net.Conn, v any) error {
	b, err := json.Marshal(v)
	if err != nil {
		return err
	}
	_, err = conn.Write(append(b, '\n'))
	return err
}

func main() {
	addr := getenv("GAME_ADDR", ":7777")
	httpAddr := getenv("HTTP_ADDR", ":8080")

	s := NewServer()

	go func() {
		mux := http.NewServeMux()
		mux.HandleFunc("/healthz", func(w http.ResponseWriter, r *http.Request) {
			w.WriteHeader(http.StatusOK)
			_, _ = w.Write([]byte("ok"))
		})
		mux.HandleFunc("/stats", func(w http.ResponseWriter, r *http.Request) {
			s.mu.RLock()
			defer s.mu.RUnlock()
			type stats struct {
				Clients int `json:"clients"`
				Bans    int `json:"bans"`
			}
			_ = json.NewEncoder(w).Encode(stats{Clients: len(s.clients), Bans: len(s.bans)})
		})
		srv := &http.Server{
			Addr:              httpAddr,
			Handler:           mux,
			ReadHeaderTimeout: 5 * time.Second,
		}
		log.Printf("http listening on %s", httpAddr)
		_ = srv.ListenAndServe()
	}()

	ln, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatal(err)
	}
	log.Printf("game server listening on %s", addr)

	for {
		conn, err := ln.Accept()
		if err != nil {
			continue
		}
		go s.handleConn(conn)
	}
}

func getenv(k, def string) string {
	v := strings.TrimSpace(os.Getenv(k))
	if v == "" {
		return def
	}
	return v
}